// 從 LINE body 抽出文字 / 圖片 messageId / replyToken
const body = $input.first().json.body || $input.first().json;
const event = (body.events || [])[0] || {};
const msg = event.message || {};
const replyToken = event.replyToken || '';
const type = msg.type || 'text';

let text = '';
let imageId = '';
if (type === 'image') {
  imageId = msg.id || '';
} else {
  // 文字訊息，把指令前綴砍掉
  const raw = (msg.text || '').trim();
  text = raw.replace(/^行事曆[\s:：]*/, '').trim();
}

const nowTW = new Intl.DateTimeFormat('zh-TW', { timeZone: 'Asia/Taipei', year:'numeric', month:'2-digit', day:'2-digit', weekday:'short', hour:'2-digit', minute:'2-digit', hour12:false }).format(new Date());
const todayISO = new Date().toLocaleDateString('en-CA', { timeZone: 'Asia/Taipei' }); // YYYY-MM-DD

return [{ json: { type, text, imageId, replyToken, todayISO, nowTW, hasInput: !!(text || imageId) } }];

// 把 binary 轉 base64，準備丟給 Gemini Vision
const item = $input.first();
const parsed = $('解析 LINE 輸入').first().json;
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
const b64 = buf.toString('base64');
const mimeType = item.binary?.data?.mimeType || 'image/jpeg';
return [{ json: { ...parsed, imageBase64: b64, imageMime: mimeType } }];

