// 解析 Gemini 回傳並驗證
const parsed = $('解析 LINE 輸入').first().json;
const resp = $input.first().json;

if (resp.error) {
  return [{ json: { ok: false, replyToken: parsed.replyToken, reason: `Gemini 錯誤：${resp.error.message || JSON.stringify(resp.error)}` } }];
}
const aiText = resp.candidates?.[0]?.content?.parts?.[0]?.text || '';
if (!aiText) {
  return [{ json: { ok: false, replyToken: parsed.replyToken, reason: 'Gemini 沒回內容（可能 quota 用完或圖片無法辨識）' } }];
}
let ai;
try {
  const clean = aiText.trim().replace(/^```json\s*/, '').replace(/^```\s*/, '').replace(/\s*```$/, '');
  ai = JSON.parse(clean);
} catch (e) {
  return [{ json: { ok: false, replyToken: parsed.replyToken, reason: `AI 回傳非 JSON：${aiText.slice(0,120)}` } }];
}

const title = String(ai.title || '').trim();
const start = String(ai.start || '').trim();
let end   = String(ai.end || '').trim();
const location = String(ai.location || '').trim();
const description = String(ai.description || '').trim();

if (!title) return [{ json: { ok: false, replyToken: parsed.replyToken, reason: '找不到事件標題' } }];
if (!start) return [{ json: { ok: false, replyToken: parsed.replyToken, reason: '找不到時間（請至少給日期，例：5/20 14:00 或 明天下午2點）' } }];

// 驗證 ISO
const d1 = new Date(start);
if (isNaN(d1.getTime())) return [{ json: { ok: false, replyToken: parsed.replyToken, reason: `開始時間格式錯誤：${start}` } }];
if (!end) end = new Date(d1.getTime() + 60*60*1000).toISOString().replace('Z','+00:00');
const d2 = new Date(end);
if (isNaN(d2.getTime())) return [{ json: { ok: false, replyToken: parsed.replyToken, reason: `結束時間格式錯誤：${end}` } }];

return [{ json: { ok: true, replyToken: parsed.replyToken, title, start, end, location, description } }];

