// 判讀 Calendar API 回應，組訊息（含 continueOnFail 接到的錯）
const data = $('驗證解析結果').first().json;
const resp = $input.first().json;
const fmt = iso => {
  try { return new Intl.DateTimeFormat('zh-TW',{ timeZone:'Asia/Taipei', month:'2-digit', day:'2-digit', weekday:'short', hour:'2-digit', minute:'2-digit', hour12:false }).format(new Date(iso)); }
  catch(e) { return iso; }
};

const hasErr = !!resp.error || resp.id == null;
if (hasErr) {
  let errMsg = '';
  if (typeof resp.error === 'string') errMsg = resp.error;
  else if (resp.error?.message) errMsg = resp.error.message;
  else if (resp.error?.errors?.[0]?.message) errMsg = resp.error.errors[0].message;
  else if (resp.message) errMsg = resp.message;
  else errMsg = JSON.stringify(resp).slice(0,200);
  const msg = `❌ 行事曆建立失敗\n\n原因：${errMsg}\n\n可能原因：\n• Google Calendar credential 未授權（n8n → Credentials → 點開 → 按 Connect / Sign in with Google）\n• OAuth token 過期，需重新授權\n• 該 Google 帳號未授權 Calendar scope`;
  return [{ json: { replyToken: data.replyToken, message: msg } }];
}

const link = resp.htmlLink || '';
const lines = [
  '✅ 已建立行事曆',
  '',
  `📌 ${data.title}`,
  `🕒 ${fmt(data.start)} ~ ${fmt(data.end)}`,
];
if (data.location)    lines.push(`📍 ${data.location}`);
if (data.description) lines.push(`📝 ${data.description}`);
if (link)             lines.push('', link);
return [{ json: { replyToken: data.replyToken, message: lines.join('\n') } }];

const data = $input.first().json;
return [{ json: { replyToken: data.replyToken, message: `❌ 行事曆建立失敗

原因：${data.reason}

格式範例：
• 行事曆 5/20 14:00 王先生看屋 三民區建工路123號 帶權狀
• 行事曆 明天下午3點 簽約 永慶博愛店
（也可以直接傳一張字條 / 截圖照片）` } }];
